// --- 1. INPUT ---
vec3 c1 = u_col1;
vec3 c2 = u_col2;

// --- 2. FIX BORDI (Il segreto) ---
// Usiamo la variabile 'u_isFlat' che abbiamo creato oggi.
// Il taglio nero avviene SOLO nell'anteprima 2D.
if (u_isFlat && (u < 0.0 || u > 1.0 || v < 0.0 || v > 1.0)) {
    return vec3(0.0); 
}

// --- 3. LOGICA GRADIENTE ---
float pos = v;

// clamp assicura che sulla superficie 3D i colori si estendano 
// fino ai bordi invece di fare cose strane o invertire il gradiente.
pos = clamp(pos, 0.0, 1.0);

// --- 4. OUTPUT ---
return mix(c1, c2, pos);
